## 🐛 Bug Report

Hyperlinks pointing to a place in the same document are not being read, when obtaining the cell only the text value is read. If the excel is loaded and then immediately saved, the references are lost on those hyperlinks, only the style and the text value is preserved. 

Lib version: 4.1.1

## Steps To Reproduce

Loaded the excel file from a buffer (in my case it must be a buffer), traverse through the cells and try to find a document hyperlink, it is never found.

```javascript
import exceljs from "exceljs"
import fs from "fs";

const path = "PATH_TO_EXCEL_FILE";

fs.readFile(path, async (_, readBuffer: Buffer) => {
    const workbook: exceljs.Workbook = new exceljs.Workbook();

    await workbook.xlsx.load(readBuffer);

    // Hyperlink in A1 returns undefined
    const hyperlink: string = workbook.getWorksheet("SheetName").getCell("A1").hyperlink

    // Optional
    workbook.eachSheet((worksheet: exceljs.Worksheet) => {
        worksheet.eachRow((row: exceljs.Row) => {
            row.eachCell((cell: exceljs.Cell) => {
                // The document hyperlink is never found
                if (cell.isHyperlink) {
                    console.log("HYPERLINK FOUND")
                }
            })
        })
    });
    
    const exceljsBuffer: exceljs.Buffer = await workbook.xlsx.writeBuffer({
        useSharedStrings: true, // this does not affect the result
        useStyles: true // this does not affect the result
    });
    const writeBuffer: Buffer = Buffer.from(exceljsBuffer);

    // References are lost upon saving the file
    fs.writeFile(path, writeBuffer, (_) => {
        console.log("WROTE FILE")
    });
});
```
